import React, { useState, useEffect } from 'react';
import axios from 'axios';

function OrderHistory({ token }) {
  const [orders, setOrders] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    fetchOrders();
  }, []);

  const fetchOrders = async () => {
    try {
      const res = await axios.get('/api/orders', {
        headers: { Authorization: `Bearer ${token}` }
      });
      setOrders(res.data);
    } catch (err) {
      setError('Failed to load orders');
    } finally {
      setLoading(false);
    }
  };

  if (loading) return <div className="loading">Loading orders...</div>;

  return (
    <div>
      <h1>Order History</h1>
      {error && <div className="error-message">{error}</div>}

      {orders.length === 0 ? (
        <div style={{ textAlign: 'center', padding: '40px' }}>
          <p>No orders yet</p>
        </div>
      ) : (
        <div style={{ marginTop: '20px' }}>
          {orders.map(order => (
            <div key={order._id} style={{ background: 'white', padding: '20px', marginBottom: '20px', borderRadius: '8px', boxShadow: '0 2px 8px rgba(0,0,0,0.1)' }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '15px' }}>
                <div>
                  <h3>Order ID: {order._id}</h3>
                  <p style={{ color: '#666' }}>Date: {new Date(order.createdAt).toLocaleDateString()}</p>
                </div>
                <div style={{ textAlign: 'right' }}>
                  <p style={{ fontSize: '18px', fontWeight: 'bold', color: '#ff6b6b' }}>Total: ฿{order.total}</p>
                  <p style={{
                    padding: '5px 10px',
                    background: order.status === 'pending' ? '#fff3cd' : '#d4edda',
                    color: order.status === 'pending' ? '#856404' : '#155724',
                    borderRadius: '4px',
                    display: 'inline-block'
                  }}>
                    {order.status}
                  </p>
                </div>
              </div>

              <h4>Items:</h4>
              <table className="cart-table" style={{ marginBottom: '15px' }}>
                <thead>
                  <tr>
                    <th>Product</th>
                    <th>Quantity</th>
                    <th>Price</th>
                    <th>Subtotal</th>
                  </tr>
                </thead>
                <tbody>
                  {order.items.map((item, idx) => (
                    <tr key={idx}>
                      <td>{item.productName}</td>
                      <td>{item.quantity}</td>
                      <td>฿{item.price}</td>
                      <td>฿{item.price * item.quantity}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

export default OrderHistory;
